const express = require('express');
const router = express.Router();
const db = require('../config/db');
const { auth } = require('../middleware/auth');

router.get('/summary', auth, async (req, res) => {
  try {
    const userId = req.user.id;
    const month  = parseInt(req.query.month) || new Date().getMonth() + 1;
    const year   = parseInt(req.query.year)  || new Date().getFullYear();

    // Total income this month
    const [[{ totalIncome }]] = await db.execute(
      `SELECT COALESCE(SUM(amount), 0) AS totalIncome
       FROM income
       WHERE user_id = ? AND MONTH(date) = ? AND YEAR(date) = ?`,
      [userId, month, year]
    );

    // Total expenses this month
    const [[{ totalExpenses }]] = await db.execute(
      `SELECT COALESCE(SUM(amount), 0) AS totalExpenses
       FROM expenses
       WHERE user_id = ? AND MONTH(date) = ? AND YEAR(date) = ?`,
      [userId, month, year]
    );

    // Savings goals count
    const [[goalsRow]] = await db.execute(
      `SELECT
         COUNT(*) AS total,
         SUM(CASE WHEN is_completed = 1 THEN 1 ELSE 0 END) AS completed
       FROM savings_goals
       WHERE user_id = ?`,
      [userId]
    );

    // Upcoming reminders — next 7 days
    const [upcomingReminders] = await db.execute(
      `SELECT * FROM reminders
       WHERE user_id = ? AND is_paid = 0
         AND due_date BETWEEN CURDATE() AND DATE_ADD(CURDATE(), INTERVAL 7 DAY)
       ORDER BY due_date ASC LIMIT 5`,
      [userId]
    );

    // Recent expenses
    const [recentExpenses] = await db.execute(
      `SELECT * FROM expenses
       WHERE user_id = ?
       ORDER BY date DESC LIMIT 5`,
      [userId]
    );

    // Category breakdown this month
    const [categoryBreakdown] = await db.execute(
      `SELECT category, SUM(amount) AS total
       FROM expenses
       WHERE user_id = ? AND MONTH(date) = ? AND YEAR(date) = ?
       GROUP BY category`,
      [userId, month, year]
    );

    // Last 6 months trend (income + expenses per month)
    const [monthlyTrend] = await db.execute(
      `SELECT
         m.month,
         m.year,
         COALESCE(e.expenses, 0) AS expenses,
         COALESCE(i.income,   0) AS income
       FROM (
         SELECT MONTH(date) AS month, YEAR(date) AS year FROM expenses WHERE user_id = ?
         UNION
         SELECT MONTH(date) AS month, YEAR(date) AS year FROM income   WHERE user_id = ?
       ) m
       LEFT JOIN (
         SELECT MONTH(date) AS month, YEAR(date) AS year, SUM(amount) AS expenses
         FROM expenses WHERE user_id = ?
         GROUP BY YEAR(date), MONTH(date)
       ) e ON m.month = e.month AND m.year = e.year
       LEFT JOIN (
         SELECT MONTH(date) AS month, YEAR(date) AS year, SUM(amount) AS income
         FROM income WHERE user_id = ?
         GROUP BY YEAR(date), MONTH(date)
       ) i ON m.month = i.month AND m.year = i.year
       GROUP BY m.year, m.month
       ORDER BY m.year DESC, m.month DESC
       LIMIT 6`,
      [userId, userId, userId, userId]
    );

    // Unread notifications
    const [[{ unreadNotifications }]] = await db.execute(
      `SELECT COUNT(*) AS unreadNotifications
       FROM notifications
       WHERE user_id = ? AND is_read = 0`,
      [userId]
    );

    res.json({
      totalIncome:         parseFloat(totalIncome),
      totalExpenses:       parseFloat(totalExpenses),
      balance:             parseFloat(totalIncome) - parseFloat(totalExpenses),
      savingsGoals:        { total: goalsRow.total || 0, completed: goalsRow.completed || 0 },
      upcomingReminders,
      recentExpenses,
      categoryBreakdown,
      monthlyTrend:        monthlyTrend.reverse(),
      unreadNotifications,
    });
  } catch (err) {
    console.error('Dashboard error:', err);
    res.status(500).json({ message: 'Dashboard failed', error: err.message });
  }
});

module.exports = router;
